(gen_random_uuid(), 'DELETE con IN', 'Elimina usuarios de La Paz o Cochabamba.', 'MEDIUM', 'DELETE', 'DELETE FROM usuarios WHERE ciudad IN (''La Paz'', ''Cochabamba'')', true, NOW()),
(gen_random_uuid(), 'LEFT JOIN con IS NULL', 'Obtén usuarios sin pedidos.', 'MEDIUM', 'JOIN', 'SELECT u.nombre FROM usuarios u LEFT JOIN pedidos p ON u.id = p.id_usuario WHERE p.id IS NULL', true, NOW()),
(gen_random_uuid(), 'JOIN con WHERE y ORDER BY', 'Obtén pedidos completados con usuario ordenados.', 'MEDIUM', 'JOIN', 'SELECT u.nombre, p.total FROM usuarios u INNER JOIN pedidos p ON u.id = p.id_usuario WHERE p.estado = ''completado'' ORDER BY p.total DESC', true, NOW()),
(gen_random_uuid(), 'GROUP BY con SUM y AVG', 'Obtén suma y promedio de edad por ciudad.', 'MEDIUM', 'GROUP_BY', 'SELECT ciudad, SUM(edad), AVG(edad) FROM usuarios GROUP BY ciudad', true, NOW()),
(gen_random_uuid(), 'GROUP BY con MAX y WHERE', 'Obtén edad máxima por ciudad de activos.', 'MEDIUM', 'GROUP_BY', 'SELECT ciudad, MAX(edad) FROM usuarios WHERE activo = true GROUP BY ciudad', true, NOW()),
(gen_random_uuid(), 'HAVING con MIN', 'Obtén ciudades con edad mínima mayor a 15.', 'MEDIUM', 'HAVING', 'SELECT ciudad, MIN(edad) FROM usuarios GROUP BY ciudad HAVING MIN(edad) > 15', true, NOW()),
