(gen_random_uuid(), 'HAVING con múltiples agregaciones', 'Obtén ciudades con más de 2 usuarios y edad promedio > 25.', 'HARD', 'HAVING', 'SELECT ciudad, COUNT(*), AVG(edad) FROM usuarios GROUP BY ciudad HAVING COUNT(*) > 2 AND AVG(edad) > 25', true, NOW()),
